@function grid($units, $counter)
      $half-gutter: false
      @if $counter == 0
        $half-gutter: true
      @if $counter > $columns
        $counter: 1
      @if $counter < 1
        $counter: 1

      $grid-return: 0 // zero out grid return

      // Left to right grid
      @if $scale-grid-direction == ltr
        @for $i from 1 through $units
          $grid-return: $grid-return + nth($ms-grid-list, abs($columns - $counter) + 1)
          // the only difference between rtl and ltr is this
          $counter: $counter + 1
          @if $i == $units
            @if $counter == 0
              $half-gutter: true
            @if $half-gutter
              @return $grid-return - ($calculated-gutter / 2)
            @return $grid-return - $calculated-gutter


      // Right to left grid
      @if $scale-grid-direction == rtl
        @for $i from 1 through $units
          $grid-return: $grid-return + nth($ms-grid-list, $counter)
          // the only difference between rtl and ltr is this
          $counter: $counter + 1
          @if $i == $units
            @if $counter == 0
              $half-gutter: true
            @if $half-gutter
              @return $grid-return - ($calculated-gutter / 2)
            @return $grid-return - $calculated-gutter

=grid-span($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $padding: $padding)
  float: left
  width: grid-span($span, $location, $columns, $gutter)

  // add special left padding
  @if type-of($columns) == list
    @if type-of(nth($columns, $location)) == list
      padding-left: nth(nth($columns, $location), 2)
      +box-sizing(border-box)
    @else if $padding != 0
      padding-left: $padding
      +box-sizing(border-box)
    // add special right padding
    @if type-of(nth($columns, ($location + $span - 1))) == list
      padding-right: nth(nth($columns, ($location + $span - 1)), 2)
      +box-sizing(border-box)
    @else if $padding != 0
      padding-right: $padding
      +box-sizing(border-box)

  @else
    +grid-padding($padding)

  // bump up the counter
  $grid-counter: $location + $span
  @if $grid-counter > column-count($columns)
    $grid-counter: 1
  @else
    margin-right: $gutter
  @if $padding != 0
    +grid-padding($padding)

=structure-float($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $grouped-styles: false)
  @if $dir == ltr or $dir == both
    @if $location > 1 and $location < column-count($columns)
      margin-right: -100%
      float: left
      margin-left: grid-span($location - 1, 1, $columns, $gutter) + $gutter
    @if $location == 1
      margin-right: -100%
      float: left
      margin-left: 0
    @if $location == column-count($columns)
      float: right
      margin-right: 0
  @if $dir == rtl
    @if $location > 1 and $location < column-count($columns)
      margin-left: -100%
      float: right
      margin-right: grid-span($location - 1, 1, $columns, $gutter) + $gutter
    @if $location == 1
      margin-left: -100%
      float: right
      margin-right: 0
    @if $location == column-count($columns)
      float: left
      margin-left: 0
  @if $dir == both
    #{$rtl-selector} &
      @if $location > 1 and $location < column-count($columns)
        margin-left: -100%
        float: right
        margin-right: grid-span($location - 1, 1, $columns, $gutter) + $gutter
      @if $location == 1
        margin-left: -100%
        float: right
        margin-right: 0
      @if $location == column-count($columns)
        float: left
        margin-left: 0

@function sort($list, $compare: compare.string(), $center: auto, $separator: auto)

	@if meta.type-of($compare) != 'function'
		@error parameter-type.parameter-type('sort', 'compare', $compare, 'function')

	@if is-separator-invalid.is-separator-invalid($separator)
		@error separator.separator('sort')

	@if $separator == 'auto' and meta.type-of($list) == 'map'
		$separator: 'comma'

	$length: list.length($list)

	@if $center != auto

		@if meta.type-of($center) != 'number'
			@error parameter-type.parameter-type('sort', 'center', $center, 'number')

		@if $center < 0 or $center > 0
			@error parameter.parameter('Must be "auto" or zero with or without units', 'sort', 'center')

	@else
		$item: find.find($list, meta.get-function('_is-number-and-not-unitless'))
		$center: if($item == null, 0, $item - $item)

	@if $length < 2
		@if meta.type-of($list) == 'map'
			@return list.join($list, (), $separator)
		@else
			@return $list

	$middle: math.floor(math.div($length, 2))
	$left: slice.slice($list, 1, $middle)
	$right: slice.slice($list, $middle + 1)

	@return _order(sort($left, $compare, $center), sort($right, $compare, $center), $compare, $center, $separator)

@function parse($value)
  @if (meta.is-list($value))
    @return $value
  @else if (not meta.is-string($value))
    @error 'Can be parsed only string type (Param: #{$value})'

  $result: null
  $divider: 0
  $operator: string.slice($value, 1, 1)
  $negative: ($operator == '-')

  // Remove operator character from value.
  $value: if($operator == '+' or $operator == '-', string.slice($value, 2), $value)

  @for $i from 1 through string.length($value)
    $char-str: string.slice($value, $i, $i)
    $char-num: -get-number-($char-str)

    @if not (meta.is-number($char-num) or $char-str == '.')
      @if (meta.is-number($result))
        $unit: string.slice($value, $i)
        $result: if($negative, $result * -1, $result)
        $result: if(unit.is($unit), unit.add($result, $unit), $result)
      @return $result

    $result: if(meta.is-number($result), $result, 0)

    @if $char-str == '.'
      $divider: 1
    @else if $divider == 0
      $result: $result * 10 + $char-num
    @else
      $divider: $divider * 10
      $result: $result + math.div($char-num, $divider)
  @return if($negative, $result * -1, $result)

=container($override: ())
  position: relative
  margin: 0 auto
  // The order is always XS -> XXS -> SM... Because XXS has to overrule the priority of XS!
  // XS (Both are active without breakpoint, because xs is the bootstrap standard...)
  @if (map-has-key($override, xs))
    width: map-get($override, xs)
  @else
    width: calc(#{$sassyContainerWidthXs} - #{$sassyContainerMarginXs})
  +bpXxs
    @if (map-has-key($override, xxs))
      width: map-get($override, xxs)
    @else
      width: calc(#{$sassyContainerWidthXxs} - #{$sassyContainerMarginXxs})
  +bpSmAndBigger()
    @if (map-has-key($override, sm))
      width: map-get($override, sm)
    @else
      width: $sassyContainerWidthSm
  +bpMdAndBigger()
    @if (map-has-key($override, md))
      width: map-get($override, md)
    @else
      width: $sassyContainerWidthMd
  +bpLgAndBigger()
    @if (map-has-key($override, lg))
      width: map-get($override, lg)
    @else
      width: $sassyContainerWidthLg
  +bpXl()
    @if (map-has-key($override, xl))
      width: map-get($override, xl)
    @else
      width: $sassyContainerWidthXl

@function sort($list, $compare: compare.string(), $center: auto, $separator: auto)

	@if meta.type-of($compare) != 'function'
		@error parameter-type.parameter-type('sort', 'compare', $compare, 'function')

	@if is-separator-invalid.is-separator-invalid($separator)
		@error separator.separator('sort')

	@if $separator == 'auto' and meta.type-of($list) == 'map'
		$separator: 'comma'

	$length: list.length($list)

	@if $center != auto

		@if meta.type-of($center) != 'number'
			@error parameter-type.parameter-type('sort', 'center', $center, 'number')

		@if $center < 0 or $center > 0
			@error parameter.parameter('Must be "auto" or zero with or without units', 'sort', 'center')

	@else
		$item: find.find($list, meta.get-function('_is-number-and-not-unitless'))
		$center: if(sass($item == null): 0; else: $item - $item)

	@if $length < 2
		@if meta.type-of($list) == 'map'
			@return list.join($list, (), $separator)
		@else
			@return $list

	$middle: math.floor(math.div($length, 2))
	$left: slice.slice($list, 1, $middle)
	$right: slice.slice($list, $middle + 1)

	@return _order(sort($left, $compare, $center), sort($right, $compare, $center), $compare, $center, $separator)

=grid-span($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $padding: $padding)
  float: left
  width: grid-span($span, $location, $columns, $gutter)

  // add special left padding
  @if type-of(nth($columns, $location)) == list
    padding-left: nth(nth($columns, $location), 2)
  @elseif $padding != 0
    padding-left: $padding
  // add special right padding
  @if type-of(nth($columns, ($location + $span - 1))) == list
    padding-right: nth(nth($columns, ($location + $span - 1)), 2)
  @elseif $padding != 0
    padding-right: $padding

  // if no special padding, apply box sizing, else apply regular padding
  @if type-of(nth($columns, $location)) or type-of(nth($columns, ($location + $span - 1))) == list
    +box-sizing(border-box)
  @else
    +grid-padding($padding)

  // bump up the counter
  $grid-counter: $location + $span
  @if $grid-counter > column-count($columns)
    $grid-counter: 1
  @else
    margin-right: $gutter
  @if $padding != 0
    +grid-padding($padding)

