@mixin sassy-button-hover($first-color, $second-color, $style)

  @if $style == "matte"
    &:hover
      background-color: darken($second-color, 5%)
      @include background(linear-gradient(color-stops(darken($first-color, 5%) 3%, darken($second-color, 5%) 75%)))
    &:active
      @include sassy-button-active-shadow($second-color)
  @if $style == "shiny"
    &:hover
      background-color: $second-color
      @include background(linear-gradient(color-stops(darken($first-color, 2%), $second-color 50%, darken($second-color, 8%))))
    &:active
      @include sassy-button-active-shadow($second-color)
  @if $style == "glass"
    &:hover
      background-color: darken($second-color, 7%)
      @include background(linear-gradient(color-stops(darken($first-color, 7%) 50%, darken($second-color, 7%) 51%)))
    &:active
      @include sassy-button-active-shadow($second-color)
  @if $style == "simple"
    &:hover
      background-color: darken($second-color, 5%)
      @include background(linear-gradient(color-stops(darken($first-color, 5%),darken($second-color, 5%))))
    &:active
      @include sassy-button-active-shadow($second-color)
  @if $style == "flat"
    &:hover
      background-color: darken($first-color, 5%)
    &:active
      background-color: darken($first-color, 8%)

@mixin -triangle-($direction, $color: null, $width: null, $height: null)
  @include size(0, 0)
  border-style: solid

  @if $height == null
    @if list.contains($-equal-dir-, $direction)
      $height: to-fixed(sqrt(sqr($width) - sqr(div($width, 2))), 4)
    @else
      $height: $width

  // Logic for each individual direction.
  @if $direction == 'top'
    @include -top-triangle-($color, $width, $height)
  @else if $direction == 'bottom'
    @include -bottom-triangle-($color, $width, $height)
  @else if $direction == 'right'
    @include -right-triangle-($color, $width, $height)
  @else if $direction == 'left'
    @include -left-triangle-($color, $width, $height)
  @else if $direction == 'top-left'
    @include -top-left-triangle-($color, $width, $height)
  @else if $direction == 'top-right'
    @include -top-right-triangle-($color, $width, $height)
  @else if $direction == 'bottom-left'
    @include -bottom-left-triangle-($color, $width, $height)
  @else if $direction == 'bottom-right'
    @include -bottom-right-triangle-($color, $width, $height)
  @else
    @error 'Direction `#{$direction}` is not supported'
